validators.command:
python3 -c "import json; d=json.load(open('.docs-ops/sdk-surface/flutter.json')); assert d.get('extractor','').startswith('flutter-hybrid'), f'wrong extractor: {d.get("extractor")}'; total_types=0; total_enum_vals=0; total_members=0; 
for lib in d.get('libraries',{}).values(): 
  types=lib.get('types',{}) if isinstance(lib,dict) else {}
  total_types += len(types)
  for t in types.values(): 
    members=t.get('members',[]) if isinstance(t,dict) else []
    total_members += len(members)
    if isinstance(t,dict) and t.get('kind')=='enum': 
      total_enum_vals += len([m for m in members if (m.get('kind') if isinstance(m,dict) else '') in ('enum_value','constant')])
assert total_types > 300, f'expected >300 types, got {total_types}'; 
assert total_members > 1500, f'expected >1500 members, got {total_members}'; 
print(f'OK types={total_types} members={total_members} enum_values={total_enum_vals}')"
